#include <iostream>using namespace std;int main(){    int n;    cout << "Enter a number to check it is prime or not: \n";    cin >> n;    bool isPrime = true;    if (n <= 1)    {        isPrime = false;    }    for (int i = 2; i * i <= n; i++)    {        if (n % i == 0)        {            isPrime = false;        }        break;    }    if (isPrime)    {        cout << "The given number" << " " << n << " is prime number";    }    else    {        cout << "The given number" << " " << n << " is not a prime number";    }    return 0}
